          currency: 'ETB',
          email: 'test@example.com',
          first_name: 'Test',
          last_name: 'User',
          phone_number: '0900123456',
          tx_ref: 'ECO-' + Date.now() + '-' + Math.random().toString(36).substring(2, 10) + '-' + Math.floor(Math.random() * 999999),
          onSuccess: async (response) => {
            console.log('=== CHAPA PAYMENT SUCCESS CALLBACK TRIGGERED ===');
            console.log('Payment success response:', response);

            alert('Payment callback triggered! Check console for details.');

            // Create order after successful payment
            console.log('Creating order with data:', {
              user_id: currentUser?.id || 1,
