              <button 
                type="button" 
                className="btn-secondary" 
                onClick={() => setShowForgotPassword(false)}
              >
                Back to Login
              </button>
            </form>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section className="section active">
      <div className="auth-container">
        <div className="auth-form">
          <h2>Login</h2>
          <form onSubmit={handleSubmit}>
            <input 
              type="email" 
