const UserProfile = ({ currentUser, setCurrentUser }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [profileData, setProfileData] = useState({
    name: currentUser.name || '',
    email: currentUser.email || '',
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });

  const handleInputChange = (e) => {
    setProfileData({
      ...profileData,
      [e.target.name]: e.target.value
    });
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();

    try {
      const updateData = {
        userId: currentUser.id,
        name: profileData.name,
        email: profileData.email
      };

      // If changing password, include password data
      if (profileData.newPassword) {
        if (profileData.newPassword !== profileData.confirmPassword) {
          alert('New passwords do not match');
          return;
        }
        if (!profileData.currentPassword) {
          alert('Please enter your current password');
          return;
        }
        updateData.currentPassword = profileData.currentPassword;
        updateData.newPassword = profileData.newPassword;
      }

      const response = await axios.put(`${API_BASE}/auth/profile`, updateData);

      if (response.data.success) {
        // Update current user data
        const updatedUser = {
          ...currentUser,
          name: profileData.name,
          email: profileData.email
        };
        setCurrentUser(updatedUser);
        localStorage.setItem('currentUser', JSON.stringify(updatedUser));

        alert('Profile updated successfully!');
        setIsEditing(false);
        setProfileData({
          ...profileData,
          currentPassword: '',
          newPassword: '',
          confirmPassword: ''
        });
      } else {
        alert(response.data.message || 'Failed to update profile');
      }
    } catch (error) {
      console.error('Profile update error:', error);
      alert('Failed to update profile');
    }
  };

  const cancelEdit = () => {
    setIsEditing(false);
    setProfileData({
      name: currentUser.name || '',
      email: currentUser.email || '',
      currentPassword: '',
      newPassword: '',
      confirmPassword: ''
    });
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>My Profile</h2>

        <div className="profile-container">
          <div className="profile-info">
            <div className="profile-header">
              <div className="profile-avatar">
                <i className="fas fa-user-circle"></i>
              </div>
              <div className="profile-details">
                <h3>{currentUser.name}</h3>
                <p>{currentUser.email}</p>
                <span className="user-role">{currentUser.role}</span>
              </div>
            </div>

            {!isEditing ? (
              <div className="profile-view">
                <div className="info-group">
                  <label>Full Name:</label>
                  <p>{currentUser.name}</p>
                </div>
                <div className="info-group">
                  <label>Email Address:</label>
                  <p>{currentUser.email}</p>
                </div>
                <div className="info-group">
                  <label>Account Type:</label>
                  <p>{currentUser.role}</p>
                </div>
                <div className="info-group">
                  <label>Member Since:</label>
                  <p>{currentUser.created_at ? new Date(currentUser.created_at).toLocaleDateString() : 'N/A'}</p>
                </div>

                <button 
                  className="btn-primary"
                  onClick={() => setIsEditing(true)}
                >
                  Edit Profile
                </button>
              </div>
            ) : (
              <div className="profile-edit">
                <form onSubmit={handleUpdateProfile}>
                  <h4>Edit Profile Information</h4>

                  <div className="form-group">
                    <label>Full Name:</label>
                    <input
                      type="text"
                      name="name"
                      value={profileData.name}
                      onChange={handleInputChange}
                      required
                    />
                  </div>

                  <div className="form-group">
                    <label>Email Address:</label>
                    <input
                      type="email"
                      name="email"
                      value={profileData.email}
                      onChange={handleInputChange}
                      required
                    />
                  </div>

                  <h4>Change Password (Optional)</h4>

                  <div className="form-group">
                    <label>Current Password:</label>
                    <input
                      type="password"
                      name="currentPassword"
                      value={profileData.currentPassword}
                      onChange={handleInputChange}
                      placeholder="Enter current password to change"
                    />
                  </div>

                  <div className="form-group">
                    <label>New Password:</label>
                    <input
                      type="password"
                      name="newPassword"
                      value={profileData.newPassword}
                      onChange={handleInputChange}
                      placeholder="Enter new password"
                    />
                  </div>

                  <div className="form-group">
                    <label>Confirm New Password:</label>
                    <input
                      type="password"
                      name="confirmPassword"
                      value={profileData.confirmPassword}
                      onChange={handleInputChange}
                      placeholder="Confirm new password"
                    />
                  </div>

                  <div className="form-buttons">
                    <button type="submit" className="btn-primary">
                      Save Changes
                    </button>
                    <button 
                      type="button" 
                      className="btn-secondary"
                      onClick={cancelEdit}
                    >
                      Cancel
                    </button>
                  </div>
                </form>
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

const SellerRegister = ({ currentUser, setCurrentSection }) => {
