              <li>✅ Only 10% commission</li>
            </ul>
          </div>
        </div>
      </div>
    </section>
  );
};

const Register = () => {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [passwordStrength, setPasswordStrength] = useState('');

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });

    if (name === 'password') {
      checkPasswordStrength(value);
    }
  };

  const checkPasswordStrength = (password) => {
    if (password.length < 6) {
      setPasswordStrength('weak');
    } else if (password.length < 8 || !/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(password)) {
      setPasswordStrength('medium');
    } else {
      setPasswordStrength('strong');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      alert('Passwords do not match');
      return;
    }

    if (passwordStrength === 'weak') {
      alert('Password is too weak. Use at least 6 characters.');
      return;
    }

    try {
      const response = await axios.post(`${API_BASE}/auth/register`, {
        fullName: formData.fullName,
        email: formData.email,
        password: formData.password
      });

      if (response.data.success) {
        alert('Registration successful! Please login.');
        window.location.reload();
      } else {
        alert(response.data.message || 'Registration failed');
      }
    } catch (error) {
      console.error('Registration error:', error);
      alert('Registration failed. Please try again.');
    }
  };

  return (
    <section className="section active">
      <div className="auth-container">
        <div className="auth-form">
          <h2>Register</h2>
          <form onSubmit={handleSubmit}>
            <input 
              type="text" 
              name="fullName"
              placeholder="Full Name"
              value={formData.fullName}
              onChange={handleInputChange}
              required 
            />
            <input 
              type="email" 
              name="email"
              placeholder="Email"
              value={formData.email}
              onChange={handleInputChange}
              required 
            />
            <input 
              type="password" 
              name="password"
              placeholder="Password"
              value={formData.password}
              onChange={handleInputChange}
              required 
            />
            {formData.password && (
              <div className={`password-strength ${passwordStrength}`}>
                Password strength: {passwordStrength}
              </div>
            )}
            <input 
              type="password" 
              name="confirmPassword"
              placeholder="Confirm Password"
              value={formData.confirmPassword}
              onChange={handleInputChange}
              required 
            />
            <button type="submit" className="btn-primary">Register</button>
          </form>
        </div>
      </div>
    </section>
  );
};

const Admin = ({ products, loadProducts }) => {
  const [activeTab, setActiveTab] = useState('products');
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [salesReport, setSalesReport] = useState(null);
  const [showAddProduct, setShowAddProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);
  const [productForm, setProductForm] = useState({
    name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''
  });

  useEffect(() => {
    if (activeTab === 'users') loadUsers();
    if (activeTab === 'orders') loadOrders();
    if (activeTab === 'reports') loadSalesReport();
  }, [activeTab]);

  const loadUsers = async () => {
    try {
      console.log('Loading users...');
      const response = await axios.get(`${API_BASE}/admin/users`);
      console.log('Users response:', response.data);
      setUsers(response.data);
    } catch (error) {
      console.error('Error loading users:', error);
      alert('Error loading users: ' + error.message);
    }
  };

  const loadOrders = async () => {
    try {
      console.log('Loading orders...');
      const response = await axios.get(`${API_BASE}/admin/orders`);
      console.log('Orders response:', response.data);
      setOrders(response.data);
    } catch (error) {
      console.error('Error loading orders:', error);
      alert('Error loading orders: ' + error.message);
    }
  };

  const loadSalesReport = async () => {
    try {
      console.log('Loading sales report...');
      const response = await axios.get(`${API_BASE}/admin/sales-report`);
      console.log('Sales report response:', response.data);
      setSalesReport(response.data);
    } catch (error) {
      console.error('Error loading sales report:', error);
      alert('Error loading sales report: ' + error.message);
    }
  };

  const deleteUser = async (userId) => {
    if (confirm('Are you sure you want to delete this user?')) {
      try {
        await axios.delete(`${API_BASE}/admin/users/${userId}`);
        loadUsers();
        alert('User deleted successfully');
      } catch (error) {
        alert('Error deleting user');
      }
    }
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        await axios.put(`${API_BASE}/admin/products/${editingProduct.id}`, productForm);
        alert('Product updated successfully');
      } else {
        await axios.post(`${API_BASE}/admin/products`, productForm);
        alert('Product added successfully');
      }
      setShowAddProduct(false);
      setEditingProduct(null);
      setProductForm({name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''});
      loadProducts();
    } catch (error) {
      alert('Error saving product');
    }
  };

  const editProduct = (product) => {
    setEditingProduct(product);
    setProductForm({
      name: product.name,
      description: product.description,
      price: product.price,
      stock: product.stock,
      category_id: product.category_id,
      image_url: product.image_url
    });
    setShowAddProduct(true);
  };

  const deleteProduct = async (productId) => {
    if (confirm('Are you sure you want to delete this product?')) {
      try {
        await axios.delete(`${API_BASE}/admin/products/${productId}`);
        loadProducts();
        alert('Product deleted successfully');
      } catch (error) {
        alert('Error deleting product');
      }
    }
  };

  const updateOrderStatus = async (orderId, status) => {
    try {
      await axios.put(`${API_BASE}/admin/orders/${orderId}/status`, {status});
      loadOrders();
      alert('Order status updated');
    } catch (error) {
      alert('Error updating order status');
    }
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>Admin Panel</h2>

        <div className="admin-tabs">
          <button 
            className={`tab-btn ${activeTab === 'products' ? 'active' : ''}`}
            onClick={() => setActiveTab('products')}
          >
            Products
          </button>
          <button 
            className={`tab-btn ${activeTab === 'users' ? 'active' : ''}`}
            onClick={() => setActiveTab('users')}
          >
            Users
          </button>
          <button 
            className={`tab-btn ${activeTab === 'orders' ? 'active' : ''}`}
            onClick={() => setActiveTab('orders')}
          >
            Orders
          </button>
          <button 
            className={`tab-btn ${activeTab === 'reports' ? 'active' : ''}`}
            onClick={() => setActiveTab('reports')}
          >
            Sales Reports
          </button>
        </div>

        {activeTab === 'products' && (
          <div className="admin-content">
            <div className="admin-header">
              <h3>Manage Products</h3>
              <button 
                className="btn-primary"
                onClick={() => setShowAddProduct(true)}
              >
                Add New Product
              </button>
            </div>

            {showAddProduct && (
              <div className="product-form">
                <h4>{editingProduct ? 'Edit Product' : 'Add New Product'}</h4>
                <form onSubmit={handleProductSubmit}>
                  <input
                    type="text"
                    placeholder="Product Name"
                    value={productForm.name}
                    onChange={(e) => setProductForm({...productForm, name: e.target.value})}
                    required
                  />
                  <textarea
                    placeholder="Description"
                    value={productForm.description}
                    onChange={(e) => setProductForm({...productForm, description: e.target.value})}
                    required
                  />
                  <input
                    type="number"
                    placeholder="Price (ETB)"
                    value={productForm.price}
                    onChange={(e) => setProductForm({...productForm, price: e.target.value})}
                    required
                  />
                  <input
                    type="number"
                    placeholder="Stock Quantity"
                    value={productForm.stock}
                    onChange={(e) => setProductForm({...productForm, stock: e.target.value})}
                    required
                  />
                  <select
                    value={productForm.category_id}
                    onChange={(e) => setProductForm({...productForm, category_id: e.target.value})}
                  >
                    <option value="1">Electronics</option>
                    <option value="2">Clothing</option>
                    <option value="3">Home</option>
                  </select>
                  <input
                    type="url"
                    placeholder="Image URL"
                    value={productForm.image_url}
                    onChange={(e) => setProductForm({...productForm, image_url: e.target.value})}
                    required
                  />
                  <div className="form-buttons">
                    <button type="submit" className="btn-primary">
                      {editingProduct ? 'Update Product' : 'Add Product'}
                    </button>
                    <button 
                      type="button" 
                      className="btn-secondary"
                      onClick={() => {
                        setShowAddProduct(false);
                        setEditingProduct(null);
                        setProductForm({name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''});
                      }}
                    >
                      Cancel
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="products-grid">
              {products.map(product => (
                <div key={product.id} className="product-card">
                  <img src={product.image_url} alt={product.name} className="product-image" />
                  <div className="product-info">
                    <div className="product-name">{product.name}</div>
                    <div className="product-price">{parseFloat(product.price).toFixed(2)} ETB</div>
                    <div>Stock: {product.stock}</div>
                    <div style={{marginTop: '1rem'}}>
                      <button 
                        className="btn-primary"
                        onClick={() => editProduct(product)}
                      >
                        Edit
                      </button>
                      <button 
                        className="btn-primary" 
                        style={{background: '#dc3545', marginLeft: '0.5rem'}}
                        onClick={() => deleteProduct(product.id)}
                      >
                        Delete
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="admin-content">
            <h3>Manage Users</h3>
            <div className="users-table">
              <table>
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Name</th>
                    <th>Email</th>
                    <th>Role</th>
                    <th>Created</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(user => (
                    <tr key={user.id}>
                      <td>{user.id}</td>
                      <td>{user.name}</td>
                      <td>{user.email}</td>
                      <td>{user.role}</td>
                      <td>{new Date(user.created_at).toLocaleDateString()}</td>
                      <td>
                        <button 
                          className="btn-danger"
                          onClick={() => deleteUser(user.id)}
                        >
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="admin-content">
            <h3>Manage Orders</h3>
            <div className="orders-table">
              {orders.map(order => (
                <div key={order.id} className="order-card">
                  <div className="order-header">
                    <h4>Order #{order.id}</h4>
                    <select 
                      value={order.status}
                      onChange={(e) => updateOrderStatus(order.id, e.target.value)}
                      className="status-select"
                    >
                      <option value="pending">Pending</option>
                      <option value="shipped">Shipped</option>
                      <option value="delivered">Delivered</option>
                      <option value="cancelled">Cancelled</option>
                    </select>
                  </div>
                  <div className="order-details">
                    <p><strong>Customer:</strong> {order.customer_name} ({order.customer_email})</p>
                    <p><strong>Total:</strong> {parseFloat(order.total).toFixed(2)} ETB</p>
                    <p><strong>Payment:</strong> {order.payment_method}</p>
                    <p><strong>Items:</strong> {order.items}</p>
                    <p><strong>Address:</strong> {order.shipping_address}</p>
                    <p><strong>Date:</strong> {new Date(order.created_at).toLocaleDateString()}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'reports' && (
          <div className="admin-content">
            <h3>Sales Reports</h3>
            {salesReport && (
              <div className="sales-summary">
                <div className="summary-cards">
                  <div className="summary-card">
                    <h4>Total Orders</h4>
                    <p className="summary-number">{salesReport.summary.total_orders}</p>
                  </div>
                  <div className="summary-card">
                    <h4>Total Revenue</h4>
                    <p className="summary-number">{parseFloat(salesReport.summary.total_revenue || 0).toFixed(2)} ETB</p>
                  </div>
                </div>

                <div className="daily-report">
                  <h4>Daily Sales (Last 30 Days)</h4>
                  <table>
                    <thead>
                      <tr>
                        <th>Date</th>
                        <th>Orders</th>
                        <th>Revenue</th>
                      </tr>
                    </thead>
                    <tbody>
                      {salesReport.daily_data.map(day => (
                        <tr key={day.order_date}>
                          <td>{new Date(day.order_date).toLocaleDateString()}</td>
                          <td>{day.total_orders}</td>
                          <td>{parseFloat(day.total_revenue).toFixed(2)} ETB</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </section>
  );
};

const getCategoryIcon = (categoryName) => {
  const icons = {
    'Electronics': 'laptop',
    'Clothing': 'tshirt',
    'Home': 'home'
  };
  return icons[categoryName] || 'box';
};

export default App;
